    54→// AI-generate professional offer letter
    55→router.post('/offers/:id/generate-letter', authMiddleware, async (req, res) => {
    56→  try {
    57→    // Get offer with all related data
    58→    const offerResult = await pool.query(
    59→      `SELECT o.*,
    60→        u.name as candidate_name,
    61→        u.email as candidate_email,
    62→        j.title as job_title,
    63→        j.description as job_description,
    64→        j.location as job_location,
    65→        r.name as recruiter_name
    66→      FROM offers o
    67→      JOIN users u ON o.candidate_id = u.id
    68→      LEFT JOIN jobs j ON o.job_id = j.id
    69→      LEFT JOIN users r ON o.recruiter_id = r.id
    70→      WHERE o.id = $1 AND o.company_id = $2`,
    71→      [req.params.id, req.user.company_id]
    72→    );
    73→
    74→    if (offerResult.rows.length === 0) {
    75→      return res.status(404).json({ error: 'Offer not found' });
    76→    }
    77→
    78→    const offer = offerResult.rows[0];
    79→
    80→    const prompt = `Generate a professional, formal employment offer letter. Return ONLY the HTML content (no markdown, no code fences). Use clean, semantic HTML with inline styles for professional formatting.
    81→
    82→OFFER DETAILS:
    83→- Company Name: ${offer.company_name || 'The Company'}
    84→- Candidate Name: ${offer.candidate_name}
    85→- Job Title: ${offer.job_title || offer.title}
    86→- Annual Salary: $${Number(offer.salary).toLocaleString()}
    87→- Start Date: ${offer.start_date ? new Date(offer.start_date).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }) : 'To be determined'}
    88→- Employment Type: ${offer.employment_type || 'Full-time'}
    89→- Location: ${offer.location || offer.job_location || 'To be discussed'}
    90→- Reporting To: ${offer.reporting_to || 'Department Manager'}
    91→- Benefits: ${offer.benefits || 'Standard company benefits package'}
    92→- Recruiter/HR Contact: ${offer.recruiter_name || 'HR Department'}
    93→
    94→REQUIREMENTS:
    95→1. Professional business letter format with company letterhead area at top
    96→2. Today's date: ${new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}
    97→3. Formal greeting to the candidate by name
    98→4. Opening paragraph expressing excitement about extending the offer
    99→5. Position details section (title, department, reporting structure, start date)
   100→6. Compensation section (salary, pay frequency)
   101→7. Benefits section (list the provided benefits professionally)
   102→8. Employment terms (at-will employment, contingencies like background check)
   103→9. Acceptance section with a placeholder line for signature and date
   104→10. Warm closing from the company
   105→11. Use inline CSS styles for clean formatting (the HTML will be rendered directly)
   106→12. Use a professional color scheme (dark navy #1e3a5f for headers, #333 for body text)
   107→13. Include proper spacing, margins, and a clean border/outline for the document
   108→14. The document should look like a real PDF offer letter when rendered
   109→
   110→FORMAT RULES:
   111→- Wrap everything in a single <div> with max-width: 800px and margin: 0 auto
   112→- Use a subtle border and padding to frame the letter
   113→- Company name at top should be bold and prominent
   114→- Include horizontal rules to separate sections
   115→- The signature block should have clear lines for name, signature, and date`;
