  1919→function escapeHtmlServer(text) {
  1920→  if (!text) return '';
  1921→  const map = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;' };
  1922→  return String(text).replace(/[&<>"']/g, m => map[m]);
  1923→}
